const body = $input.first().json.body || $input.first().json;

const user_id       = body.user_id       || null;
const email         = body.email         || null;
const business_name = body.business_name || 'your business';
const operator_name = body.operator_name || 'Your AI Operator';
const plan_tier     = (body.plan_tier || 'free').toLowerCase();
const active_tools  = Array.isArray(body.active_tools) ? body.active_tools : [];
const dashboard_url = body.dashboard_url || `/dashboard/${user_id}`;

if (!user_id) throw new Error('Missing required field: user_id');
if (!email)   throw new Error('Missing required field: email');

// Tool display metadata for personalised email content
const toolMeta = {
  launchpad_tool_1:  { name: 'AI Lead Finder',       description: 'Find and qualify high-intent prospects automatically', emoji: '🎯' },
  launchpad_tool_2:  { name: 'Copy Generator',        description: 'Generate conversion-ready copy for any channel',      emoji: '✍️' },
  launchpad_tool_3:  { name: 'Offer Builder',         description: 'Structure irresistible offers that close faster',      emoji: '🔥' },
  launchpad_tool_4:  { name: 'Email Sequencer',       description: 'Build automated follow-up that books calls for you',   emoji: '📧' },
  launchpad_tool_5:  { name: 'Funnel Mapper',         description: 'Visualise and optimise your entire sales funnel',      emoji: '🗺️' },
  launchpad_tool_6:  { name: 'Competitor Analyst',    description: 'Reverse-engineer what is working for top competitors', emoji: '🔍' },
  launchpad_tool_7:  { name: 'Ad Creative Studio',    description: 'Produce scroll-stopping ad concepts in minutes',       emoji: '🎨' },
  launchpad_tool_8:  { name: 'VSL Script Writer',     description: 'Write high-converting video sales letter scripts',     emoji: '🎬' },
  launchpad_tool_9:  { name: 'AI Sales Closer',       description: 'AI-powered objection handling and close scripts',      emoji: '💰' },
  launchpad_tool_10: { name: 'Business Automator',    description: 'Automate your entire back-office operation',           emoji: '⚡' }
};

const planLabels = {
  free:    'Free',
  starter: 'Starter',
  pro:     'Pro',
  scale:   'Scale'
};

// Pick top tool for Day 1 email focus
const primary_tool_key  = active_tools[0] || 'launchpad_tool_2';
const secondary_tool_key = active_tools[1] || 'launchpad_tool_1';
const primary_tool   = toolMeta[primary_tool_key]   || toolMeta['launchpad_tool_2'];
const secondary_tool = toolMeta[secondary_tool_key] || toolMeta['launchpad_tool_1'];

// Upgrade CTA based on plan
const upgradeCTAs = {
  free:    { cta: 'Upgrade to Starter for 100 credits and 5 tools', link: 'https://nova-ops.space/upgrade/starter' },
  starter: { cta: 'Upgrade to Pro for 500 credits and full Nova OS', link: 'https://nova-ops.space/upgrade/pro' },
  pro:     { cta: 'Upgrade to Scale for unlimited credits and team seats', link: 'https://nova-ops.space/upgrade/scale' },
  scale:   { cta: null, link: null }
};

const upgrade = upgradeCTAs[plan_tier] || upgradeCTAs['free'];
const app_base = process.env.APP_BASE_URL || 'https://app.nova-ops.space';
const full_dashboard_url = `${app_base}${dashboard_url}`;

return [{
  json: {
    user_id,
    email,
    business_name,
    operator_name,
    plan_tier,
    plan_label:          planLabels[plan_tier] || 'Free',
    active_tools,
    dashboard_url:       full_dashboard_url,
    primary_tool_key,
    primary_tool,
    secondary_tool_key,
    secondary_tool,
    upgrade_cta:         upgrade.cta,
    upgrade_link:        upgrade.link,
    now:                 new Date().toISOString()
  }
}];

